var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"놀랍군. 이성을 잃은 것 같아 보이지만 적과 아군을 확실하게 구분해서 베고 있어.","JPN":"これは驚いた。理性を無くしたように見えるが、敵と味方を確実に見分けて斬っている。","ENG":"Impressive. While she seems to have lost cognition, she is able to identify enemies and allies apart.","TWN":"真驚人，看似失去理智，攻擊時卻還能清楚分別敵我。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"게다가 저 힘은…… 단순히 적신인자의 효과라고 하기엔 격차가 크다.","JPN":"それにあの力は……単なるクリムゾン・ファクターの効果というには差がありすぎる。","ENG":"And that strength... Far more powerful than the basic effect of the embedded factor.","TWN":"而且她的力量之大……不單純是適神因子的效果。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"어쩌면 내가 상정하지 못한 변수가 있는 건가?","JPN":"もしかすると私が想定していない変数があるのか？","ENG":"Perhaps there is a variable that I might have missed?","TWN":"難道是我沒計算到的變數？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아하핫, 무식하게 날뛰는 모습이 그야말로 짐승이네.","JPN":"あははっ、無知性で暴れてるところなんて獣そっくり。","ENG":"Ah ha ha, look at her go berserk. A true savage, no?","TWN":"哈哈哈，根本是野獸吧，在那橫衝直撞的。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ff3636>크아아아아!!!!</color>","JPN":"<color=#ff3636>クアアアア！！！！</color>","ENG":"<color=#ff3636>Gwaaaah!!!</color>","TWN":"<color=#ff3636>呃啊啊啊阿！！！！</color>"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"저 흑색의 검은…… 설마 명부검?","JPN":"あの黒色の剣は……まさか冥府剣？","ENG":"That dark blade... Could it be the Nether God’s Sword?","TWN":"那把黑色的劍……難道是冥府劍？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그때 환상종 여인이 가지고 있던 검이군. 아는 물건이오?","JPN":"あの時幻想種の女が持っていた刀だな。知っているのか？","ENG":"It was the sword that the Bygone female was holding. Is it something familiar to you?","TWN":"是上次那個夢幻類女生拿的劍，你知道這把劍？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"알다마다. 명부신의 자손들이 역신을 베기 위해 벼려낸 명부신의 검이지.","JPN":"もちろん知っておるとも。冥府の神の子孫が疫病神を斬るために鍛えた冥府の神の刀だ。","ENG":"Of course it is. It was used by the Nether God to slay the Plague God.","TWN":"當然知道，那是冥府神的後裔鑄造來斬殺瘟神的劍。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"오랫동안 미완성인 상태라고 들었는데, 그럼에도 저런 엄청난 위력을 발휘할 줄이야.","JPN":"長らく未完成のままだと聞いていたが、それでもあんな威力を発揮するとは。","ENG":"I heard that it was left unfinished for a long time... but even in that state, its powers seem impeccable.","TWN":"但我聽說一直處於未完成的狀態，沒想到可以發揮如此大的威力。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"신의 검이라…… 그렇다면 왜 저렇게 강해졌는지도 납득이 되는군.","JPN":"神の剣か……それならどうしてあんなに強くなったのかも納得がいく。","ENG":"A god’s sword... That explains the massive increase in power.","TWN":"神之劍嗎……那就不難理解為何會有如此威力。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그렇게 마냥 감탄하고 있을 상황은 아닌 것 같은데.","JPN":"そんなに感心している場合ではないぞ。","ENG":"This is not the time to stand and watch in awe.","TWN":"現在不是讚嘆的時候吧？"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그 무모한 실험 때문에 아까운 전력들이 전부 쓸려나가고 있지 않나?","JPN":"その無茶な実験のせいで貴重な戦力が全部失われようとしているではないか。","ENG":"Your troops are getting butchered because of your reckless experiment.","TWN":"因為你那衝動的實驗，一直在耗損那些珍貴的戰力！"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"희생을 두려워하면 이상적인 실험 결과를 얻기 힘들다오.","JPN":"犠牲を恐れていては理想的な実験結果を得ることは難しい。","ENG":"The fear of loss is what keeps us away from the ideal.","TWN":"害怕犧牲，就無法得到理想的實驗結果。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하지만, 슬슬 실험의 전제를 바꿔보는 것도 괜찮겠지.","JPN":"だが、そろそろ実験の前提を変えてみるのもいいだろう。","ENG":"Nevertheless... It would be a valid notion to change the prerequisites of the experiment.","TWN":"不過稍微改變一下實驗的條件也無妨。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"레노어, 시작하거라.","JPN":"レノア、始めろ。","ENG":"Begin, Lenore.","TWN":"蕾諾雅，開始吧。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"네, 아버지.","JPN":"はい、お父様。","ENG":"Yes, father.","TWN":"是，父親。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"흣…… 우후훗……","JPN":"ふっ……うふふっ……","ENG":"Heh... Fu fu fu...","TWN":"呵……呵呵呵……"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};